import android.content.Context
import android.content.DialogInterface
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.os.Handler
import android.os.Looper
import android.widget.EditText
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        // Assume activity_main.xml is set up for login screen if needed
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences("app_prefs", Context.MODE_PRIVATE)

        // If already authenticated, bypass login
        if (sharedPreferences.getBoolean("authenticated", false)) {
            navigateToHome()
            return
        }

        // Check if device supports biometric authentication
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate()) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                showBiometricPrompt()
            }
            else -> {
                // Fallback to password prompt if biometric is not available
                showPasswordFallback()
            }
        }
    }

    private fun showBiometricPrompt() {
        executor = ContextCompat.getMainExecutor(this)
        biometricPrompt = BiometricPrompt(this, executor, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                // Save authenticated flag
                sharedPreferences.edit().putBoolean("authenticated", true).apply()
                navigateToHome()
            }

            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                // For certain error cases, you might decide to fallback to password
                showPasswordFallback()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                // Optionally handle failure, here we fallback to password after a delay
                Handler(Looper.getMainLooper()).postDelayed({ showPasswordFallback() }, 500)
            }
        })

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Fingerprint Authentication")
            .setSubtitle("Place your finger on the sensor")
            .setDescription("Authenticate using your fingerprint or enter password")
            .setNegativeButtonText("Use Password")
            .build()

        biometricPrompt.authenticate(promptInfo)
    }

    private fun showPasswordFallback() {
        val passwordInput = EditText(this)
        val dialog = AlertDialog.Builder(this)
            .setTitle("Password Authentication")
            .setMessage("Enter your password")
            .setView(passwordInput)
            .setPositiveButton("OK") { dialogInterface: DialogInterface, i: Int ->
                val password = passwordInput.text.toString()
                // Replace "password123" with your actual password validation
                if (password == "password123") {
                    sharedPreferences.edit().putBoolean("authenticated", true).apply()
                    navigateToHome()
                } else {
                    AlertDialog.Builder(this)
                        .setTitle("Authentication Failed")
                        .setMessage("Invalid password. Please try again.")
                        .setPositiveButton("OK") { d, _ ->
                            d.dismiss()
                            showPasswordFallback()
                        }
                        .show()
                }
            }
            .setNegativeButton("Cancel") { dialogInterface, i ->
                dialogInterface.dismiss()
            }
            .setCancelable(false)
            .create()

        dialog.show()
    }

    private fun navigateToHome() {
        // Navigate to home screen or next activity
        // For demonstration, we'll just start HomeActivity
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        // Assume activity_home.xml displays the home screen
        setContentView(R.layout.activity_home)
    }
